class Solution {
    int hist(vector<int>& h) {
        stack<int> st; int ans=0; h.push_back(-1);
        for (int i=0;i<(int)h.size();i++) {
            while (!st.empty() && h[st.top()]>h[i]) {
                int H=h[st.top()]; st.pop();
                ans=max(ans, H*(st.empty()?i:i-st.top()-1));
            }
            st.push(i);
        }
        h.pop_back(); return ans;
    }
public:
    int maximalRectangle(vector<vector<char>>& m) {
        if (m.empty()) return 0;
        int n=m[0].size(), ans=0; vector<int> h(n);
        for (auto& row: m) {
            for (int j=0;j<n;j++) h[j]= row[j]=='1'? h[j]+1:0;
            ans=max(ans, hist(h));
        }
        return ans;
    }
};
